mapper.select:
SELECT so.id, so.drug_id, d.drug_name, d.spec AS drug_spec, so.batch_id, sb.batch_no, sb.expire_date, so.out_type, CASE so.out_type WHEN 1 THEN '销售' WHEN 2 THEN '损耗' WHEN 3 THEN '退货' ELSE '未知' END AS out_type_name, so.quantity, so.retail_price, so.cost_price, so.total_amount, so.operator_id, u.username AS operator_username, so.remark, so.create_time FROM stock_out_table so LEFT JOIN drug_table d ON so.drug_id = d.id LEFT JOIN stock_batch_table sb ON so.batch_id = sb.id LEFT JOIN user_table u ON so.operator_id = u.id
AND so.drug_id = #{drugId}
AND so.out_type = #{outType}
AND DATE(so.create_time) >= #{startDate}
AND DATE(so.create_time) <= #{endDate}
ORDER BY so.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM stock_out_table so


        AND so.drug_id = #{drugId}


        AND so.out_type = #{outType}


        AND DATE(so.create_time) >= #{startDate}


        AND DATE(so.create_time) <= #{endDate}

SELECT COALESCE(SUM(CASE WHEN out_type = 1 THEN total_amount ELSE 0 END), 0) AS total_sales_amount, COALESCE(SUM(cost_price * quantity), 0) AS total_cost_amount, COALESCE(SUM(CASE WHEN out_type = 1 THEN total_amount ELSE 0 END) - SUM(cost_price * quantity), 0) AS total_profit FROM stock_out_table
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
